"use strict";
/* ============================================================
   ÉTAT — session uniquement, aucune persistance.
   ============================================================ */
const state = {
  us: [],          // {id, num}
  rels: [],        // {from, to, type}  type ∈ sur|eq|equ (normalisés)
  nextId: 1,
  selection: null, // {fromId, type} en cours
  ordreH: {},      // id de groupe -> index horizontal (mise en page seule)
  alignement: [],  // liste d'ids d'US à empiler sur une même colonne verticale
  xAlignement: null,// x de la colonne d'alignement (déplaçable)
  modeAlign: false,// vrai quand on sélectionne les US à aligner
  precedentH: null,// instantané {ordreH,alignement,xAlignement} avant le dernier déplacement, pour « Annuler »
};

/* ---------- Onglets ---------- */
/* ============================================================
   NAVIGATION — écran d'accueil ↔ volets
   L'architecture des volets est inchangée ; seul le point d'accès
   passe d'une barre d'onglets à un écran d'accueil.
   ============================================================ */
const accueil = document.getElementById('accueil');
const btnAccueil = document.getElementById('btn-accueil');
const entete = document.getElementById('entete');

function allerVolet(v){
  document.querySelectorAll('section.volet').forEach(x=>x.classList.remove('actif'));
  accueil.classList.remove('actif');
  document.getElementById('v-'+v).classList.add('actif');
  btnAccueil.hidden = false;
  entete.classList.add('compact');
  window.scrollTo(0,0);
}
function allerAccueil(){
  document.querySelectorAll('section.volet').forEach(x=>x.classList.remove('actif'));
  accueil.classList.add('actif');
  btnAccueil.hidden = true;
  entete.classList.remove('compact');
  // un retour à l'accueil referme toute fiche mémo ouverte, pour repartir
  // sur la liste au prochain accès au volet « Mémos ».
  if(memoDetail && !memoDetail.hidden){ memoDetail.hidden = true; memosListe.hidden = false; }
  window.scrollTo(0,0);
}
// cartes de l'accueil
document.querySelectorAll('.accueil-carte').forEach(c=>{
  c.addEventListener('click',()=>allerVolet(c.dataset.go));
});
// bouton retour accueil dans l'en-tête
btnAccueil.addEventListener('click',allerAccueil);
// onglets conservés (masqués) : restent fonctionnels si réaffichés un jour
document.querySelectorAll('nav.onglets button').forEach(b=>{
  b.addEventListener('click',()=>allerVolet(b.dataset.v));
});

/* ============================================================
   VOLET 1 — HARRIS
   ============================================================ */
const grille   = document.getElementById('grille');
const consigne = document.getElementById('consigne');
const feuille  = document.getElementById('feuille');

function setConsigne(html){ consigne.innerHTML = html; }

function ajouterUS(num){
  if(state.us.length>=20){ setConsigne('Maximum de <strong>20 US</strong> atteint.'); return; }
  state.us.push({id:state.nextId++, num: num||''});
  rendreBlocs();
}

function supprimerUS(id){
  state.us = state.us.filter(u=>u.id!==id);
  state.rels = state.rels.filter(r=>r.from!==id && r.to!==id);
  if(state.selection && state.selection.fromId===id) annulerSelection();
  rendreBlocs();
}

function libelleType(t){ return {sur:'sur',sous:'sous',coupe:'coupe',remplit:'remplit',post:'sur',eq:'=',equ:'equ.'}[t]; }
function numDe(id){ const u=state.us.find(x=>x.id===id); return u? (u.num||'?') : '?'; }

function rendreBlocs(){
  grille.innerHTML='';
  state.us.forEach(u=>{
    const bloc=document.createElement('div');
    bloc.className='bloc-us';
    bloc.dataset.id=u.id;
    if(state.selection){
      if(state.selection.fromId===u.id) bloc.classList.add('source');
      else bloc.classList.add('cible-possible');
    }
    // relations sortantes de cette US (pour affichage)
    const relsHtml = state.rels
      .filter(r=>r.from===u.id)
      .map(r=>`<div class="r"><span><b>${libelleType(r.type)}</b> ${numDe(r.to)}</span><span class="del" data-from="${r.from}" data-to="${r.to}" data-type="${r.type}">×</span></div>`)
      .join('');

    // En phase de désignation de cible (type choisi), les numéros deviennent
    // inertes : on peut toucher n'importe où dans le rectangle sans éditer.
    const verrou = !!(state.selection && state.selection.type);
    const attrsNum = verrou ? 'readonly tabindex="-1"' : '';
    bloc.innerHTML =
      `<button class="suppr-bloc" data-suppr="${u.id}" aria-label="Supprimer">×</button>
       <div class="us-label">US</div>
       <input class="num mono${verrou?' verrou':''}" inputmode="text" ${attrsNum} value="${u.num.replace(/"/g,'&quot;')}" placeholder="n°" data-num="${u.id}">
       <button class="relier" data-relier="${u.id}">＋ relier</button>
       <div class="rels">${relsHtml}</div>`;
    grille.appendChild(bloc);
  });

  const verrouActif = !!(state.selection && state.selection.type);
  // saisie du numéro (désactivée quand on désigne une cible)
  grille.querySelectorAll('input.num').forEach(inp=>{
    inp.addEventListener('input',e=>{
      const u=state.us.find(x=>x.id===+inp.dataset.num);
      if(u){ u.num=e.target.value; }
    });
    // hors phase de cible : le champ garde le focus sans déclencher la sélection.
    // en phase de cible : on laisse le clic remonter au bloc (désignation cible).
    if(!verrouActif){ inp.addEventListener('click',e=>e.stopPropagation()); }
  });
  // suppression de bloc
  grille.querySelectorAll('.suppr-bloc').forEach(btn=>{
    btn.addEventListener('click',e=>{ e.stopPropagation(); supprimerUS(+btn.dataset.suppr); });
  });
  // suppression de relation
  grille.querySelectorAll('.rels .del').forEach(d=>{
    d.addEventListener('click',e=>{
      e.stopPropagation();
      state.rels = state.rels.filter(r=>!(r.from===+d.dataset.from && r.to===+d.dataset.to && r.type===d.dataset.type));
      invaliderDiagramme();
      rendreBlocs();
    });
  });
  // bouton "relier" -> démarre une relation depuis cette US (1er temps)
  grille.querySelectorAll('.relier').forEach(btn=>{
    btn.addEventListener('click',e=>{ e.stopPropagation(); demarrerRelation(+btn.dataset.relier); });
  });
  // clic sur le bloc -> sert uniquement à désigner la CIBLE (2e temps)
  grille.querySelectorAll('.bloc-us').forEach(bloc=>{
    bloc.addEventListener('click',()=>onClicCible(+bloc.dataset.id));
  });
}

function demarrerRelation(id){
  const u=state.us.find(x=>x.id===id);
  if(!u || !u.num.trim()){ setConsigne('Donnez d\'abord un <strong>numéro</strong> à cette US.'); return; }
  if(state.selection && state.selection.fromId===id){ annulerSelection(); return; }
  state.selection={fromId:id, type:null};
  document.getElementById('feuille-titre').textContent='Relation depuis US '+u.num;
  feuille.classList.add('ouverte');
  rendreBlocs();
}

function onClicCible(id){
  // n'agit que si une sélection est en cours ET qu'un type est choisi
  if(state.selection && state.selection.type){
    if(id===state.selection.fromId){ setConsigne('Choisissez une <strong>autre</strong> US comme cible.'); return; }
    ajouterRelation(state.selection.fromId, id, state.selection.type);
    annulerSelection();
  }
}

/* Sélecteur de relation */
feuille.querySelectorAll('.choix-rel button').forEach(b=>{
  b.addEventListener('click',()=>{
    if(!state.selection) return;
    state.selection.type=b.dataset.rel;
    feuille.classList.remove('ouverte');
    const sym=libelleType(b.dataset.rel);
    setConsigne(`US ${numDe(state.selection.fromId)} <strong>${sym}</strong> … touchez l'US à associer.`);
    rendreBlocs();
  });
});
document.getElementById('feuille-annuler').addEventListener('click',annulerSelection);

function annulerSelection(){
  state.selection=null;
  feuille.classList.remove('ouverte');
  setConsigne('Touchez un bloc pour démarrer une relation.');
  rendreBlocs();
}

function invaliderDiagramme(){
  const sortie=document.getElementById('sortie-diagramme');
  if(sortie.innerHTML.trim()!==''){
    sortie.innerHTML='<div class="consigne" style="margin:0;">Relations modifiées — touchez « Diagramme ▸ » pour régénérer.</div>';
  }
}

function ajouterRelation(from,to,type){
  // Normalisation : on stocke toute relation de succession en "sur"
  // "A sur B"   : A au-dessus / plus récent que B            -> {from:A,to:B,type:'sur'}
  // "A sous B"  : A en dessous / plus ancien que B           -> "B sur A"
  // "A coupe B"   : A recoupe B, donc postérieure (plus récent)  -> "A sur B"
  // "A remplit B" : A comble B, donc postérieure (plus récent)   -> "A sur B"
  // "=" et "equ" sont symétriques.
  let f=from,t=to,ty=type;
  if(type==='sous'){ f=to; t=from; ty='sur'; }   // A sous B  ==  B sur A
  if(type==='coupe'){ ty='sur'; }                 // A coupe B ==  A sur B
  if(type==='remplit'){ ty='sur'; }               // A remplit B == A sur B
  // éviter doublons
  const existe = state.rels.some(r=>
     (r.type===ty && r.from===f && r.to===t) ||
     ((ty==='eq'||ty==='equ') && r.type===ty && r.from===t && r.to===f));
  if(existe){ setConsigne('Cette relation existe déjà.'); rendreBlocs(); return; }
  state.rels.push({from:f,to:t,type:ty});
  setConsigne('Relation enregistrée.');
  invaliderDiagramme();
}

document.getElementById('btn-add-us').addEventListener('click',()=>ajouterUS());
document.getElementById('btn-raz').addEventListener('click',()=>{
  state.us=[];state.rels=[];state.selection=null;state.nextId=1;state.ordreH={};state.alignement=[];state.xAlignement=null;state.modeAlign=false;state.precedentH=null;
  document.getElementById('sortie-diagramme').innerHTML='';
  annulerSelection();
});
document.getElementById('btn-modifier').addEventListener('click',()=>{
  document.getElementById('sortie-diagramme').innerHTML='';
  annulerSelection();
  setConsigne('Mode édition. Modifiez les US ou relations, puis « Diagramme ▸ ».');
});
document.getElementById('btn-exemple').addEventListener('click',chargerExempleMur);

/* Exemple : mur maçonné
   tranchée de fondation -> fondation -> élévation -> comblement tranchée -> sol
   Succession (du plus ancien au plus récent) :
   creusement tranchée (1004), fondation (1003), comblement tranchée (1002),
   élévation (1001), sol (1000).  sol post. élévation, élévation post. comblement,
   comblement post. fondation, fondation post. creusement tranchée. */
function chargerExempleMur(){
  state.us=[]; state.rels=[]; state.nextId=1; state.selection=null; state.ordreH={}; state.alignement=[]; state.xAlignement=null; state.modeAlign=false; state.precedentH=null;
  // Cas à 10 US : mur avec tranchée de fondation et comblements latéraux.
  const defs=[
    {num:'1',  lbl:'terrain naturel'},
    {num:'2',  lbl:'remblai'},
    {num:'3',  lbl:'creusement tranchée'},
    {num:'4',  lbl:'fondation maçonnée'},
    {num:'5',  lbl:'élévation maçonnée'},
    {num:'6',  lbl:'comblt ouest'},
    {num:'7',  lbl:'comblt est'},
    {num:'8',  lbl:'sol'},
    {num:'9',  lbl:'abandon'},
    {num:'10', lbl:'démolition'},
  ];
  const ids={};
  defs.forEach(d=>{ const id=state.nextId++; state.us.push({id,num:d.num}); ids[d.num]=id; });
  const S=(a,b)=>state.rels.push({from:ids[a],to:ids[b],type:'sur'}); // a sur b (a au-dessus)
  S('2','1');    // remblai sur terrain naturel
  S('3','2');    // creusement de la tranchée coupe (postérieur à) le remblai
  S('4','3');    // fondation dans la tranchée, postérieure au creusement
  S('5','4');    // élévation sur fondation
  S('6','4');    // comblement ouest contre la fondation (postérieur)
  S('7','4');    // comblement est contre la fondation (postérieur)
  S('8','2');    // sol repose sur le remblai
  S('8','6');    // sol recouvre le comblement ouest
  S('8','7');    // sol recouvre le comblement est
  S('9','8');    // abandon sur le sol
  S('10','9');   // démolition sur l'abandon
  setConsigne('Exemple à 10 US chargé. Touchez « Diagramme ▸ », puis glissez les comblements 6 et 7 de part et d\'autre.');
  document.getElementById('sortie-diagramme').innerHTML='';
  rendreBlocs();
}

/* ---------- Génération de la matrice ---------- */
document.getElementById('btn-diagramme').addEventListener('click',()=>{
  state.precedentH=null;
  genererDiagramme();
});

const btnAnnulerPos=document.getElementById('btn-annuler-pos');
function majBtnAnnulerPos(){
  btnAnnulerPos.disabled = (state.precedentH===null);
}
btnAnnulerPos.addEventListener('click',()=>{
  if(!state.precedentH) return;
  state.ordreH=state.precedentH.ordreH;
  state.alignement=state.precedentH.alignement;
  state.xAlignement=state.precedentH.xAlignement;
  state.precedentH=null;
  genererDiagramme();
  setConsigne('Position précédente restaurée.');
});

document.getElementById('btn-aligner').addEventListener('click',()=>{
  const sortie=document.getElementById('sortie-diagramme');
  const btn=document.getElementById('btn-aligner');
  // Le diagramme doit exister pour aligner.
  if(sortie.querySelector('svg')===null && !state.modeAlign){
    setConsigne('Générez d\'abord le diagramme, puis touchez « Aligner ▤ ».');
    return;
  }
  state.modeAlign=!state.modeAlign;
  if(state.modeAlign){
    // Instantané de la disposition avant l'opération d'alignement, pour pouvoir « Annuler ».
    state.precedentH={ordreH:{...state.ordreH}, alignement:[...state.alignement], xAlignement:state.xAlignement};
    majBtnAnnulerPos();
    btn.classList.add('action'); btn.classList.remove('ghost');
    btn.textContent='Aligner : terminé ✓';
    setConsigne('Mode alignement : touchez les US à empiler sur une même colonne. Re-touchez pour retirer.');
  }else{
    btn.classList.remove('action'); btn.classList.add('ghost');
    btn.textContent='Aligner ▤';
    setConsigne('Alignement appliqué.');
  }
  genererDiagramme();   // régénère en tenant compte du mode et de l'alignement
});

function genererDiagramme(){
  const sortie=document.getElementById('sortie-diagramme');
  sortie.innerHTML='';
  const usValides=state.us.filter(u=>u.num.trim()!=='');
  if(usValides.length===0){ sortie.innerHTML='<div class="msg-erreur">Aucune US numérotée.</div>'; return; }

  // 1. Groupes de fusion via "=" (corrélation Harris : même US)
  const parent={}; usValides.forEach(u=>parent[u.id]=u.id);
  const find=x=>{ while(parent[x]!==x){ parent[x]=parent[parent[x]]; x=parent[x]; } return x; };
  const union=(a,b)=>{ const ra=find(a),rb=find(b); if(ra!==rb) parent[ra]=rb; };
  state.rels.filter(r=>r.type==='eq').forEach(r=>{
    if(parent[r.from]!==undefined && parent[r.to]!==undefined) union(r.from,r.to);
  });
  // groupe -> liste des num d'US
  const groupes={}; // repr -> {ids:[], nums:[]}
  usValides.forEach(u=>{ const r=find(u.id); (groupes[r]=groupes[r]||{ids:[],nums:[]}); groupes[r].ids.push(u.id); groupes[r].nums.push(u.num); });
  const reprs=Object.keys(groupes);

  // 2. Arêtes de succession ("sur") entre groupes.
  //    "A sur B" : A plus récent, au-dessus de B (B plus ancien, en dessous).
  //    dessous[a] = groupes directement SOUS a (donc plus anciens).
  const dessous={}; reprs.forEach(r=>dessous[r]=new Set());
  state.rels.filter(r=>r.type==='sur').forEach(r=>{
    if(parent[r.from]===undefined||parent[r.to]===undefined) return;
    const a=find(r.from), b=find(r.to); // a sur b -> b est sous a
    if(a!==b) dessous[a].add(b);
  });

  // 3. Détection de cycle (DFS)
  const cycle=detecterCycle(reprs,dessous,groupes);
  if(cycle){
    // Construire la boucle fermée lisible : US a « sur » US b « sur » … « sur » US a
    const seq=cycle.map(id=>groupes[id].nums.join('='));
    const chaine=seq.map((s,i)=>{
      const suiv = seq[(i+1)%seq.length];
      return `US ${s} <span style="color:var(--ocre)">sur</span> US ${suiv}`;
    }).join(' &nbsp;·&nbsp; ');
    sortie.innerHTML=
      `<div class="msg-erreur">
         <strong>Séquence impossible (boucle stratigraphique).</strong><br>
         Les relations suivantes se referment en boucle, ce qui n'a pas de sens chronologique :<br><br>
         ${chaine}<br><br>
         Une US ne peut être à la fois au-dessus et en dessous d'une autre.
         Reprenez l'une de ces relations (par ex. inversez « sur » / « sous », ou supprimez-la).
       </div>`;
    return;
  }

  // 4. Réduction transitive : retirer a->c si a->b->...->c existe
  const dessousReduit=reductionTransitive(reprs,dessous);

  // 5. Profondeur depuis chaque sommet (nb de strates SOUS lui).
  //    profondeur élevée = plus récent (placé en HAUT) ; 0 = plus ancien (en BAS).
  const prof=calculerNiveaux(reprs,dessousReduit);

  // 6. Liens de synchronisme (equ) entre groupes -> même profondeur, pointillés
  const synchros=[];
  state.rels.filter(r=>r.type==='equ').forEach(r=>{
    if(parent[r.from]===undefined||parent[r.to]===undefined) return;
    const a=find(r.from), b=find(r.to);
    if(a!==b){ synchros.push([a,b]); prof[b]=prof[a]; } // aligner visuellement
  });

  dessinerSVG(sortie,reprs,groupes,dessousReduit,prof,synchros);
}

function detecterCycle(nodes,dessus,groupes){
  const etat={}; nodes.forEach(n=>etat[n]=0); // 0 blanc 1 gris 2 noir
  let pile=[];
  function dfs(n){
    etat[n]=1; pile.push(n);
    for(const m of dessus[n]){
      if(etat[m]===1){ return pile.slice(pile.indexOf(m)); }
      if(etat[m]===0){ const c=dfs(m); if(c) return c; }
    }
    etat[n]=2; pile.pop(); return null;
  }
  for(const n of nodes){ if(etat[n]===0){ const c=dfs(n); if(c) return c; } }
  return null;
}

function reductionTransitive(nodes,dessus){
  // accessibilité indirecte
  const reach={}; nodes.forEach(n=>reach[n]=new Set());
  function explore(n,visited){
    for(const m of dessus[n]){
      if(!visited.has(m)){ visited.add(m); explore(m,visited); }
    }
  }
  nodes.forEach(n=>{ const v=new Set(); explore(n,v); reach[n]=v; });
  const reduit={}; nodes.forEach(n=>reduit[n]=new Set());
  nodes.forEach(a=>{
    for(const b of dessus[a]){
      // garder a->b seulement si b n'est pas atteignable via un autre successeur direct
      let redondant=false;
      for(const c of dessus[a]){
        if(c!==b && reach[c].has(b)){ redondant=true; break; }
      }
      if(!redondant) reduit[a].add(b);
    }
  });
  return reduit;
}

function calculerNiveaux(nodes,dessus){
  // niveau = longueur du plus long chemin depuis un sommet (récent=0 en haut)
  const niveau={}; const memo={};
  function prof(n){
    if(memo[n]!==undefined) return memo[n];
    let max=0;
    for(const m of dessus[n]){ max=Math.max(max, 1+prof(m)); }
    memo[n]=max; return max;
  }
  nodes.forEach(n=>{ niveau[n]=prof(n); });
  return niveau;
}

/* Ordre horizontal choisi par l'utilisateur, par identifiant de groupe.
   N'affecte JAMAIS la chronologie (rang vertical) : pure mise en page. */
function dessinerSVG(sortie,nodes,groupes,dessous,prof,synchros){
  const maxP=Math.max(0,...nodes.map(n=>prof[n]));
  // Dimensions adaptatives : plus il y a d'US, plus les blocs et écarts se resserrent,
  // pour que le diagramme tienne dans le cadre.
  const nb=nodes.length;
  const W  = nb<=6 ? 88 : nb<=10 ? 74 : nb<=16 ? 62 : 52;
  const H  = nb<=6 ? 46 : nb<=10 ? 40 : nb<=16 ? 34 : 30;
  const gapX = nb<=6 ? 34 : nb<=10 ? 26 : 20;
  const gapY = nb<=6 ? 64 : nb<=10 ? 52 : 44;
  const padX=24, padY=24;
  const policeBloc = nb<=6 ? 18 : nb<=10 ? 15 : nb<=16 ? 13 : 11;

  // Rang vertical (0 = haut/récent) figé par la stratigraphie.
  const rang={}; nodes.forEach(n=>{ rang[n]=maxP-prof[n]; });

  // Ordre horizontal : on part de l'ordre mémorisé (state.ordreH) s'il existe,
  // sinon de l'ordre de création. Recalé proprement par rang.
  const parRang={};
  nodes.forEach(n=>{ (parRang[rang[n]]=parRang[rang[n]]||[]).push(n); });
  Object.keys(parRang).forEach(rg=>{
    parRang[rg].sort((a,b)=>{
      const oa=(state.ordreH[a]??1e9), ob=(state.ordreH[b]??1e9);
      if(oa!==ob) return oa-ob;
      return nodes.indexOf(a)-nodes.indexOf(b);   // repli stable
    });
    // réindexer densément pour ce rang
    parRang[rg].forEach((n,i)=>{ state.ordreH[n]=i; });
  });

  const largeurMax=Math.max(...Object.values(parRang).map(a=>a.length),1);
  const svgW=padX*2 + largeurMax*W + (largeurMax-1)*gapX;
  const svgH=padY*2 + (maxP+1)*H + maxP*gapY;

  // Réserve à droite pour les canaux des liens longs. Les canaux étant placés
  // dynamiquement près des blocs traversés, on réserve une marge proportionnelle
  // au nombre de liens longs, et le conteneur autorise le défilement horizontal.
  let nbLongs=0;
  nodes.forEach(a=>{ dessous[a].forEach(b=>{ if(Math.abs(rang[b]-rang[a])>1) nbLongs++; }); });
  const margeGouttiere = nbLongs>0 ? (nbLongs*16 + 30) : 0;
  const svgWtot = svgW + margeGouttiere;

  // Calcule la position {x,y} de chaque bloc à partir de rang + ordre horizontal.
  // L'alignement impose UNIQUEMENT que les US alignées partagent la même colonne x
  // (state.xAlignement, déplaçable). Tous les autres blocs restent libres : leur x
  // suit leur ordreH, sans contrainte de côté.
  function calcPos(){
    const pos={};
    const align=(state.alignement||[]).map(String).filter(id=>nodes.includes(id));
    // Colonne d'alignement : x mémorisé, sinon défaut à gauche.
    if(align.length && (state.xAlignement==null)) state.xAlignement=padX;
    const xAlign = state.xAlignement;

    for(let rg=0; rg<=maxP; rg++){
      const arr=(parRang[rg]||[]).slice().sort((a,b)=>state.ordreH[a]-state.ordreH[b]);
      const cible=arr.find(n=>align.includes(n));   // au plus une US alignée par rang
      const libres=arr.filter(n=>n!==cible);
      const y=padY+rg*(H+gapY);

      if(cible!=null){
        // L'US alignée tient la colonne. Les libres se répartissent autour d'elle
        // selon leur ordreH : ordreH < celui de la cible -> à gauche, sinon -> à droite.
        pos[cible]={x:xAlign, y};
        const oCible=state.ordreH[cible];
        const gauche=libres.filter(n=>state.ordreH[n]<oCible);
        const droite=libres.filter(n=>state.ordreH[n]>=oCible);
        // à gauche : empilées vers la gauche depuis la colonne
        gauche.forEach((n,i)=>{ pos[n]={x:xAlign-(gauche.length-i)*(W+gapX), y}; });
        // à droite : empilées vers la droite depuis la colonne
        droite.forEach((n,i)=>{ pos[n]={x:xAlign+(i+1)*(W+gapX), y}; });
      }else{
        // rang sans US alignée : on déroule simplement par ordreH à partir d'une
        // origine cohérente avec la colonne (si elle existe) ou centrée sinon.
        const totalW=arr.length*W+(arr.length-1)*gapX;
        const x0 = (xAlign!=null) ? (xAlign - (W+gapX)) : (svgW-totalW)/2;
        arr.forEach((n,i)=>{ pos[n]={x:x0+i*(W+gapX), y}; });
      }
    }
    return pos;
  }

  const NS='http://www.w3.org/2000/svg';
  const svg=document.createElementNS(NS,'svg');
  svg.setAttribute('viewBox',`0 0 ${svgWtot} ${svgH}`);
  svg.setAttribute('role','img');
  svg.setAttribute('aria-label','Matrice de Harris (blocs déplaçables horizontalement)');
  svg.style.touchAction='pan-y';   // permet le scroll vertical, on gère l'horizontal
  svg.innerHTML=`<style>
      .bloc{fill:#F5F1E6;stroke:#3A2E25;stroke-width:2;cursor:grab;}
      .bloc.drag{cursor:grabbing;fill:#F0E7D2;stroke:#9C5A3C;}
      .bloc.aligne{fill:#E9DcC2;stroke:#9C5A3C;stroke-width:3;}
      .lbl{font-family:monospace;font-size:${policeBloc}px;font-weight:700;fill:#3A2E25;text-anchor:middle;pointer-events:none;}
      .lien{stroke:#3A2E25;stroke-width:2;fill:none;}
      .lien-long{stroke:#3A2E25;stroke-width:2;}
      .sync{stroke:#9C5A3C;stroke-width:2;stroke-dasharray:6 4;}
    </style>`;

  const gLiens=document.createElementNS(NS,'g');
  const gBlocs=document.createElementNS(NS,'g');
  svg.appendChild(gLiens); svg.appendChild(gBlocs);

  // Redessine liens + blocs depuis les positions courantes.
  let pos=calcPos();
  const elBloc={}, elTxt={};
  // viewBox courant, recalculé à chaque redraw pour épouser le contenu.
  let vb={x:0,y:0,w:svgWtot,h:svgH};

  // Construit la liste des segments {x1,y1,x2,y2,orient,lien} d'un tracé orthogonal
  // décrit par une suite de points. orient = 'h' (horizontal) ou 'v' (vertical).
  function segmentsDe(points, lienId, classe){
    const segs=[];
    for(let i=0;i<points.length-1;i++){
      const [ax,ay]=points[i], [bx,by]=points[i+1];
      if(ay===by && ax!==bx) segs.push({x1:ax,y1:ay,x2:bx,y2:by,orient:'h',lienId,classe});
      else if(ax===bx && ay!==by) segs.push({x1:ax,y1:ay,x2:bx,y2:by,orient:'v',lienId,classe});
      else if(ax!==bx && ay!==by){ // segment oblique éventuel : tel quel, pas de pont
        segs.push({x1:ax,y1:ay,x2:bx,y2:by,orient:'o',lienId,classe});
      }
    }
    return segs;
  }

  function redraw(){
    // (le routage des liens longs est calculé plus bas, canal par canal)

    // 1) Construire tous les tracés sous forme de listes de points, puis de segments.
    // Pour les liens longs, on place le canal vertical juste à droite des blocs
    // effectivement traversés (rangs intermédiaires), au lieu du bord de page :
    // le détour reste minimal et s'adapte après alignement.
    let segs=[];
    let lienSeq=0;
    // x du bord droit le plus avancé parmi les rangs strictement entre a et b
    function bordDroitTraverse(ra,rb){
      const lo=Math.min(ra,rb), hi=Math.max(ra,rb);
      let xmax=0;
      for(let rg=lo+1; rg<hi; rg++){
        (parRang[rg]||[]).forEach(n=>{ if(pos[n]) xmax=Math.max(xmax,pos[n].x+W); });
      }
      return xmax;
    }
    // Un bloc d'un rang intermédiaire bloque-t-il le couloir vertical [xmin,xmax] ?
    function couloirBloque(ra,rb,xmin,xmax){
      const lo=Math.min(ra,rb), hi=Math.max(ra,rb);
      for(let rg=lo+1; rg<hi; rg++){
        for(const n of (parRang[rg]||[])){
          if(!pos[n]) continue;
          const bx1=pos[n].x, bx2=pos[n].x+W;
          // chevauchement horizontal avec le couloir du lien
          if(bx2 > xmin-2 && bx1 < xmax+2) return true;
        }
      }
      return false;
    }
    // attribuer à chaque lien long un canal, en empilant ceux qui partagent la zone
    const canauxAttribues=[];
    nodes.forEach(a=>{
      dessous[a].forEach(b=>{
        const pa=pos[a], pb=pos[b]; if(!pa||!pb) return;
        const x1=pa.x+W/2, y1=pa.y+H, x2=pb.x+W/2, y2=pb.y;
        const saut=Math.abs(rang[b]-rang[a]);
        const id='L'+(lienSeq++);
        let points;
        if(saut<=1){
          const ym=(y1+y2)/2;
          points=[[x1,y1],[x1,ym],[x2,ym],[x2,y2]];
          segs=segs.concat(segmentsDe(points,id,'lien'));
        }else if(!couloirBloque(rang[a],rang[b], Math.min(x1,x2), Math.max(x1,x2))){
          // Couloir vertical libre : descente directe, sans canal latéral.
          // (coude minimal seulement si x1 ≠ x2)
          if(Math.abs(x1-x2)<2){
            points=[[x1,y1],[x2,y2]];
          }else{
            const ym=(y1+y2)/2;
            points=[[x1,y1],[x1,ym],[x2,ym],[x2,y2]];
          }
          segs=segs.concat(segmentsDe(points,id,'lien lien-long'));
        }else{
          // Couloir occupé : contourner par un canal latéral à droite des blocs traversés.
          const bord=bordDroitTraverse(rang[a],rang[b]);
          let gx=Math.max(bord, Math.max(x1,x2)) + 18;
          while(canauxAttribues.some(c=>Math.abs(c-gx)<16)) gx+=16;
          gx=Math.min(gx, svgWtot-8);
          canauxAttribues.push(gx);
          const TOL=6;
          const yBas = Math.abs(gx-x1)<TOL ? y1 : y1+18;
          const yHaut= Math.abs(gx-x2)<TOL ? y2 : y2-18;
          points=[[x1,y1],[x1,yBas],[gx,yBas],[gx,yHaut],[x2,yHaut],[x2,y2]];
          points=points.filter((p,i)=> i===0 || p[0]!==points[i-1][0] || p[1]!==points[i-1][1]);
          segs=segs.concat(segmentsDe(points,id,'lien lien-long'));
        }
      });
    });

    // 2) Détecter les croisements : segment horizontal d'un lien × segment vertical
    //    d'un AUTRE lien. On note, pour chaque horizontal, les x où poser un pont.
    const ponts={}; // index segment horizontal -> [x de croisement, ...]
    segs.forEach((h,ih)=>{
      if(h.orient!=='h') return;
      const hxmin=Math.min(h.x1,h.x2), hxmax=Math.max(h.x1,h.x2), hy=h.y1;
      segs.forEach(v=>{
        if(v.orient!=='v' || v.lienId===h.lienId) return;
        const vymin=Math.min(v.y1,v.y2), vymax=Math.max(v.y1,v.y2), vx=v.x1;
        // croisement strict (on évite les contacts aux extrémités exactes)
        if(vx>hxmin+0.5 && vx<hxmax-0.5 && hy>vymin+0.5 && hy<vymax-0.5){
          (ponts[ih]=ponts[ih]||[]).push(vx);
        }
      });
    });

    // 3) Émettre les segments. Les horizontaux avec ponts sont découpés et
    //    enjambent chaque croisement par un petit demi-cercle (arc SVG).
    let out='';
    const R=4; // rayon du pont
    segs.forEach((s,i)=>{
      if(s.orient==='o'){
        out+=`<path class="${s.classe}" d="M${s.x1} ${s.y1} L${s.x2} ${s.y2}"/>`;
        return;
      }
      if(s.orient==='v'){
        out+=`<path class="${s.classe}" d="M${s.x1} ${s.y1} L${s.x2} ${s.y2}"/>`;
        return;
      }
      // horizontal : insérer les arcs aux x de croisement
      const xs=(ponts[i]||[]).slice().sort((p,q)=> (s.x1<=s.x2? p-q : q-p));
      const dir = s.x1<=s.x2 ? 1 : -1;
      let d=`M${s.x1} ${s.y1}`;
      let cur=s.x1;
      xs.forEach(xc=>{
        const avant=xc-dir*R, apres=xc+dir*R;
        d+=` L${avant} ${s.y1}`;
        // demi-cercle : sweep choisi pour bomber vers le haut quel que soit le sens
        const sweep = dir>0 ? 1 : 0;
        d+=` A${R} ${R} 0 0 ${sweep} ${apres} ${s.y1}`;
        cur=apres;
      });
      d+=` L${s.x2} ${s.y2}`;
      out+=`<path class="${s.classe}" d="${d}"/>`;
    });

    // 4) Synchronismes (pointillés), inchangés.
    synchros.forEach(([a,b])=>{
      const pa=pos[a], pb=pos[b]; if(!pa||!pb) return;
      const [g,dd]= pa.x<=pb.x ? [pa,pb]:[pb,pa];
      out+=`<line class="sync" x1="${g.x+W}" y1="${g.y+H/2}" x2="${dd.x}" y2="${dd.y+H/2}"/>`;
    });

    gLiens.innerHTML=out;
    nodes.forEach(n=>{
      const p=pos[n];
      elBloc[n].setAttribute('x',p.x); elBloc[n].setAttribute('y',p.y);
      elTxt[n].setAttribute('x',p.x+W/2); elTxt[n].setAttribute('y',p.y+H/2+policeBloc*0.35);
      // marquer visuellement les blocs alignés UNIQUEMENT en mode alignement
      const cls = (state.modeAlign && state.alignement.includes(n)) ? 'bloc aligne' : 'bloc';
      if(elBloc[n].getAttribute('class')!==cls && !elBloc[n].classList.contains('drag')){
        elBloc[n].setAttribute('class',cls);
      }
    });

    // Recadrage dynamique : le viewBox épouse le contenu réel (blocs + canaux),
    // avec une marge. Plus aucun débordement, quelle que soit la disposition.
    let minx=Infinity, maxx=-Infinity, miny=Infinity, maxy=-Infinity;
    nodes.forEach(n=>{
      const p=pos[n]; if(!p) return;
      minx=Math.min(minx,p.x); maxx=Math.max(maxx,p.x+W);
      miny=Math.min(miny,p.y); maxy=Math.max(maxy,p.y+H);
    });
    canauxAttribues.forEach(cx=>{ maxx=Math.max(maxx,cx+4); minx=Math.min(minx,cx-4); });
    if(!isFinite(minx)){ minx=0; maxx=200; miny=0; maxy=200; }
    const m=padX;
    vb.x=minx-m; vb.y=miny-m; vb.w=(maxx-minx)+2*m; vb.h=(maxy-miny)+2*m;
    svg.setAttribute('viewBox',`${vb.x} ${vb.y} ${vb.w} ${vb.h}`);
  }

  // créer les blocs
  nodes.forEach(n=>{
    const r=document.createElementNS(NS,'rect');
    r.setAttribute('class','bloc'); r.setAttribute('width',W); r.setAttribute('height',H); r.setAttribute('rx',2);
    r.dataset.id=n;
    const t=document.createElementNS(NS,'text');
    t.setAttribute('class','lbl'); t.textContent=groupes[n].nums.join(' = ');
    gBlocs.appendChild(r); gBlocs.appendChild(t);
    elBloc[n]=r; elTxt[n]=t;
  });
  redraw();

  /* -------- Glissement horizontal (souris + tactile) -------- */
  let drag=null; // {id, rg, startClientX, baseX}
  function clientToSvgX(clientX){
    const rect=svg.getBoundingClientRect();
    return vb.x + (clientX-rect.left)*(vb.w/rect.width);
  }
  function onDown(e){
    const id=e.target.dataset && e.target.dataset.id;
    if(!id) return;
    // Mode alignement : le clic sélectionne/désélectionne l'US pour la colonne.
    if(state.modeAlign){
      const i=state.alignement.indexOf(id);
      if(i===-1) state.alignement.push(id); else state.alignement.splice(i,1);
      if(state.alignement.length && state.xAlignement==null) state.xAlignement=padX;
      pos=calcPos(); redraw();
      e.preventDefault(); return;
    }
    const pt=e.touches?e.touches[0]:e;
    // Instantané de la disposition avant ce déplacement, pour pouvoir « Annuler ».
    state.precedentH={ordreH:{...state.ordreH}, alignement:[...state.alignement], xAlignement:state.xAlignement};
    majBtnAnnulerPos();
    // Glisser un bloc ALIGNÉ le SORT de la colonne : il redevient libre, là où on le pose.
    if(state.alignement.includes(id)){
      state.alignement=state.alignement.filter(x=>x!==id);
      if(state.alignement.length===0) state.xAlignement=null;
      pos=calcPos();
    }
    drag={id, rg:rang[id], baseX:pos[id].x, startX:clientToSvgX(pt.clientX)};
    elBloc[id].classList.add('drag');
    e.preventDefault();
  }
  function onMove(e){
    if(state.modeAlign) return;   // pas de glissement en mode alignement
    if(!drag) return;
    const pt=e.touches?e.touches[0]:e;
    const dx=clientToSvgX(pt.clientX)-drag.startX;

    // Bloc libre : position visuelle libre, puis réordonnancement par x parmi
    // TOUS les voisins du rang (alignés inclus) pour pouvoir passer à gauche/droite.
    pos[drag.id]={x:drag.baseX+dx, y:pos[drag.id].y};
    const voisins=(parRang[drag.rg]||[]).filter(x=>x!==drag.id)
                   .sort((a,b)=>state.ordreH[a]-state.ordreH[b]);
    const cx=pos[drag.id].x;
    let idx=0;
    voisins.forEach(v=>{ if(cx > pos[v].x) idx++; });
    voisins.splice(idx,0,drag.id);
    voisins.forEach((v,i)=>{ state.ordreH[v]=i; });
    // recalculer les positions (le bloc tiré garde sa position libre le temps du drag)
    const recompute=calcPos();
    Object.keys(recompute).forEach(k=>{ if(k!==drag.id) pos[k]=recompute[k]; });
    redraw();
    pos[drag.id]={x:drag.baseX+dx, y:pos[drag.id].y};
    elBloc[drag.id].setAttribute('x',pos[drag.id].x);
    elTxt[drag.id].setAttribute('x',pos[drag.id].x+W/2);
    e.preventDefault();
  }
  function onUp(){
    if(!drag) return;
    elBloc[drag.id].classList.remove('drag');
    drag=null;
    pos=calcPos();   // recaler proprement les positions
    redraw();        // redraw recalcule aussi le viewBox englobant
  }
  svg.addEventListener('mousedown',onDown);
  window.addEventListener('mousemove',onMove);
  window.addEventListener('mouseup',onUp);
  svg.addEventListener('touchstart',onDown,{passive:false});
  svg.addEventListener('touchmove',onMove,{passive:false});
  svg.addEventListener('touchend',onUp);

  sortie.innerHTML='';
  const aide=document.createElement('div');
  aide.className='consigne';
  aide.style.margin='0 0 10px';
  if(state.modeAlign){
    aide.innerHTML='<strong>Mode alignement</strong> : touchez les US à empiler sur une même colonne (re-touchez pour retirer). Touchez « Aligner : terminé ✓ » pour sortir.';
  }else if((state.alignement||[]).length){
    aide.innerHTML='Colonne alignée active. Glissez les autres blocs latéralement ; relancez « Aligner ▤ » pour modifier la colonne.';
  }else{
    aide.innerHTML='Glissez un bloc <strong>à gauche ou à droite</strong> pour réorganiser sa ligne. L\'ordre vertical (chronologie) reste figé.';
  }
  sortie.appendChild(aide);
  sortie.appendChild(svg);
  majBtnAnnulerPos();
}

/* ============================================================
   ALTIMÉTRIE — point de visée + points levés (coupe & structures)
   Décimales avec un POINT, deux chiffres maximum.
   ============================================================ */

/* Nettoyage de saisie : autorise chiffres et un seul point, max 2 décimales.
   Renvoie la chaîne nettoyée (ne reformate pas pendant la frappe,
   pour ne pas déplacer le curseur). */
function nettoyerDecimal(s){
  s=String(s).replace(/,/g,'.');        // virgule -> point
  s=s.replace(/[^0-9.]/g,'');           // garder chiffres et points
  const i=s.indexOf('.');
  if(i!==-1){                            // un seul point
    s=s.slice(0,i+1)+s.slice(i+1).replace(/\./g,'');
    s=s.slice(0,i+1)+s.slice(i+1,i+3);   // max 2 décimales
  }
  return s;
}
/* Applique le nettoyage à un <input> en préservant la position du curseur. */
function brancherDecimal(input,onChange){
  input.addEventListener('input',e=>{
    const avant=input.value;
    const pos=input.selectionStart;
    const apres=nettoyerDecimal(avant);
    if(apres!==avant){
      input.value=apres;
      const delta=avant.length-apres.length;
      const np=Math.max(0,pos-delta);
      try{ input.setSelectionRange(np,np); }catch(_){}
    }
    onChange();
  });
}

function parseM(v){
  if(v==null) return NaN;
  const t=String(v).trim().replace(',','.');
  if(t===''||t==='.') return NaN;
  const n=Number(t);
  return Number.isFinite(n)? n : NaN;
}
function fmt(n){ return n.toFixed(2).replace('.',','); }  // affichage : 2 décimales

const zRefInp=document.getElementById('z-ref');
const lecArrInp=document.getElementById('lec-arr');
const lecAxeInp=document.getElementById('lec-axe');
const calcLunette=document.getElementById('calc-lunette');
const calcAxe=document.getElementById('calc-axe');

function zLunette(){
  const zr=parseM(zRefInp.value), la=parseM(lecArrInp.value);
  if(!Number.isFinite(zr)||!Number.isFinite(la)) return NaN;
  return zr+la;
}
function majLunette(){
  const zr=parseM(zRefInp.value), la=parseM(lecArrInp.value);
  if(!Number.isFinite(zr)||!Number.isFinite(la)){
    calcLunette.classList.add('vide');
    calcLunette.innerHTML='Z<sub>lunette</sub> = Z<sub>réf</sub> + lecture lunette/niveau';
  }else{
    calcLunette.classList.remove('vide');
    calcLunette.innerHTML=`Z<sub>lunette</sub> = ${fmt(zr)} + ${fmt(la)} = <span class="res">${fmt(zr+la)} m</span>`;
  }
  majAxe();
  majToutesAltitudes();
}
function majAxe(){
  const zl=zLunette(), lx=parseM(lecAxeInp.value);
  if(!Number.isFinite(zl)||!Number.isFinite(lx)){
    calcAxe.classList.add('vide');
    calcAxe.innerHTML="Z<sub>axe</sub> = Z<sub>lunette</sub> − lecture sur l'axe";
  }else{
    calcAxe.classList.remove('vide');
    calcAxe.innerHTML=`Z<sub>axe</sub> = ${fmt(zl)} − ${fmt(lx)} = <span class="res">${fmt(zl-lx)} m</span>`;
  }
}
brancherDecimal(zRefInp,majLunette);
brancherDecimal(lecArrInp,majLunette);
brancherDecimal(lecAxeInp,majAxe);

/* ---------- Points levés (coupe & structures) ---------- */
const listeCoupe=document.getElementById('liste-coupe');
let coupe=[]; // {lec}

/* Recalcule UNIQUEMENT les altitudes affichées, sans toucher aux inputs
   (donc sans déplacer le curseur de saisie). */
function majToutesAltitudes(){
  const zl=zLunette();
  listeCoupe.querySelectorAll('.bloc-pt').forEach(row=>{
    const i=+row.dataset.i;
    const lec=parseM(coupe[i].lec);
    const cell=row.querySelector('.alt');
    if(Number.isFinite(zl)&&Number.isFinite(lec)){
      cell.textContent=fmt(zl-lec)+' m'; cell.classList.remove('invalide');
    }else{
      cell.textContent='—'; cell.classList.add('invalide');
    }
  });
}

/* Reconstruit la liste (ajout/suppression de lignes uniquement). */
function rebatirCoupe(){
  listeCoupe.innerHTML=coupe.map((pt,i)=>`
    <div class="bloc-pt" data-i="${i}">
      <div class="num-pt">${i+1}</div>
      <input class="lec mono" inputmode="decimal" placeholder="lecture" value="${(pt.lec||'').replace(/"/g,'&quot;')}" data-i="${i}" data-f="lec">
      <div class="alt invalide">—</div>
      <button class="x" data-del="${i}" aria-label="Supprimer">×</button>
    </div>`).join('');

  listeCoupe.querySelectorAll('input.lec').forEach(inp=>{
    brancherDecimal(inp,()=>{
      coupe[+inp.dataset.i].lec=inp.value;
      majToutesAltitudes();   // ne reconstruit pas la ligne -> curseur conservé
    });
  });
  listeCoupe.querySelectorAll('[data-del]').forEach(b=>{
    b.addEventListener('click',()=>{ coupe.splice(+b.dataset.del,1); rebatirCoupe(); });
  });
  majToutesAltitudes();
}
document.getElementById('add-coupe').addEventListener('click',()=>{
  if(coupe.length>=20) return;
  coupe.push({lec:''}); rebatirCoupe();
});

/* ---------- Export CSV ---------- */
function exportCSV(nom,entetes,lignes){
  let csv=entetes.join(';')+'\n'+lignes.map(l=>l.join(';')).join('\n');
  const blob=new Blob([csv],{type:'text/csv;charset=utf-8;'});
  const url=URL.createObjectURL(blob);
  const a=document.createElement('a');
  a.href=url; a.download=nom; document.body.appendChild(a); a.click();
  document.body.removeChild(a); URL.revokeObjectURL(url);
}
document.getElementById('exp-coupe').addEventListener('click',()=>{
  const zl=zLunette();
  const lignes=coupe.map((p,i)=>{
    const lec=parseM(p.lec);
    const alt=(Number.isFinite(zl)&&Number.isFinite(lec))?fmt(zl-lec):'';
    return [i+1, p.lec||'', alt];
  });
  exportCSV('points_leves.csv',['N° de point','Lecture (m)','Altitude (m)'],lignes);
});

/* ============================================================
   VOLET MÉMOS CHANTIER
   ------------------------------------------------------------
   Les mémos sont définis ci-dessous, intégrés au fichier (hors ligne).
   STRUCTURE d'un mémo :
     { id, titre, sousTitre, ico, sections:[...] }
   Chaque section peut être de type :
     {type:'texte',  contenu:'...'}                     -> paragraphe
     {type:'titre',  contenu:'...'}                     -> sous-titre
     {type:'liste',  items:['...','...']}               -> liste à puces
     {type:'cle',    contenu:'...'}                     -> encadré "point clé"
     {type:'figure', img:'data:image/...;base64,...', legende:'...'}
                                                        -> illustration
   POUR AJOUTER UNE IMAGE : remplacez la valeur `img` par votre image
   encodée en base64 (data URI). Tant que `img` est vide (''), un
   emplacement "illustration à venir" s'affiche à la place.
   ============================================================ */
